main: (i) => {
	function color(i) {
		if (i < 27) {
		let c = i 
		let h = c * 6 + 30
		let s = 60
		let l = 50 - c * 1.6
		let rgb = hslToRGB([h,s,l])
		return colorHelper(rgb[0], rgb[1], rgb[2])
}
		if (i - 100 > -1) {
		let c = i - 100
		let h = c * 6 + 30
		let s = 40
		let l = 30 - 5 * c
		let rgb = hslToRGB([h,s,l])
		return colorHelper(rgb[0], rgb[1], rgb[2])
}
	}


function hslToRGB(hsl) {
  const h = hsl[0];
  const s = hsl[1] / 100;
  const l = hsl[2] / 100;
  const k = (n) => (n + h / 30) % 12;
  const a = s * Math.min(l, 1 - l);
  const f = (n) =>
    l - a * Math.max(-1, Math.min(k(n) - 3, Math.min(9 - k(n), 1)));
  return [Math.floor(255 * f(0)), Math.floor(255 * f(8)), Math.floor(255 * f(4))];
}



	function colorHelper(r, g, b) {
		return b + g * 0x100 + r* 0x10000
	}
	return color(i)
}
